  type StyleProp,
  type ViewStyle,
} from 'react-native';
import { router } from 'expo-router';
import { StatusPill, type StatusPillStatus } from '@/components/primitives/StatusPill';
import { SkeletonCard } from '@/components/primitives/SkeletonCard';
import { colors, radii, shadows, spacing } from '@/design/tokens';
import { textStyles } from '@/design/typography';
import { useAuth } from '@/lib/auth';
import { supabase } from '@/lib/supabase';
import { formatRelativeTime } from '@/lib/time';
import type { Database } from '@/types/supabase';

// US-043 — Creator "My Applications" tab. Queries applications joined to
// listings + listing_versions (for the snapshot title) + users (for the
// lister handle) under the creator's JWT and groups rows into four
// segments: Pending / Approved / Rejected / Cancelled. Tap row →
// campaign detail. Spec: docs/design.md §3.1 (tab label "Applied") +
// product-plan §3 + §6 (statuses). Route path matches docs/design.md:151
// canonical URL `/(creator)/applications` (overrides the PRD's
// `applied.tsx` filename — existing TabBar wiring from US-031 wins).

type ApplicationStatus = Database['public']['Enums']['application_status'];
type Segment = 'pending' | 'approved' | 'rejected' | 'cancelled';

// Map the 6 DB enum values to 4 display buckets. `withdrawn` is a
// creator-initiated cancellation; both listing-* variants are
// lister-initiated. All three share the Cancelled segment per AC.
const STATUS_BUCKET: Record<ApplicationStatus, Segment> = {
  pending: 'pending',
  approved: 'approved',
  rejected: 'rejected',
  withdrawn: 'cancelled',
  cancelled_listing_edit: 'cancelled',
  cancelled_listing_closed: 'cancelled',
};

const SEGMENTS: readonly { key: Segment; label: string }[] = [
  { key: 'pending', label: 'Pending' },
  { key: 'approved', label: 'Approved' },
  { key: 'rejected', label: 'Rejected' },
  { key: 'cancelled', label: 'Cancelled' },
];

// Segmented control semantics: a11y role "tab" with single-select state.
// Chip primitive (checkbox role) is for multi-select filter rows — a
// segmented control needs single-select. Keeping this inline rather than
// promoting to a shared primitive until another screen needs it.
type SegmentControlProps = {
  active: Segment;
  onChange: (next: Segment) => void;
};

function SegmentControl({ active, onChange }: SegmentControlProps) {
  return (
    <View style={styles.segmentRow} accessibilityRole="tablist">
      {SEGMENTS.map((s) => (
        <SegmentButton
          key={s.key}
          label={s.label}
          selected={active === s.key}
          onPress={() => onChange(s.key)}
          testID={`segment-${s.key}`}
        />
      ))}
    </View>
  );
}

type SegmentButtonProps = {
  label: string;
  selected: boolean;
  onPress: () => void;
  testID?: string;
};

function SegmentButton({ label, selected, onPress, testID }: SegmentButtonProps) {
  const bg = selected ? colors.primarySoft : colors.surface;
  const textColor = selected ? colors.primaryDeep : colors.ink;
  return (
    <Pressable
      onPress={onPress}
      accessibilityRole="tab"
      accessibilityState={{ selected }}
      accessibilityLabel={label}
      style={[styles.segment, { backgroundColor: bg }, shadows.hard]}
      testID={testID}
    >
      <Text style={[textStyles.micro, { color: textColor }]} allowFontScaling={false}>
        {label}
      </Text>
    </Pressable>
  );
}

// Row shape for the list query — title is inside `listing_versions.snapshot`,
// lister handle is `users.username` via `listings.lister_id`. We hand-roll
// the type instead of relying on embed inference so the component stays
// readable.
type SnapshotShape = { title?: string };

type ApplicationRow = {
  id: string;
  status: ApplicationStatus;
  created_at: string;
  listing_id: string;
  listing: {
    id: string;
    lister_id: string;
    lister: { username: string } | null;
  } | null;
  version: {
    snapshot: SnapshotShape | null;
  } | null;
};

export default function Applications() {
  const { user } = useAuth();
  const userId = user?.id ?? null;

  const [segment, setSegment] = useState<Segment>('pending');
  const [rows, setRows] = useState<ApplicationRow[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const load = useCallback(async () => {
    if (!userId) return;
    setLoading(true);
    setError(null);
    const { data, error: fetchError } = await supabase
      .from('applications')
      .select(
        `
        id,
        status,
        created_at,
        listing_id,
        listing:listings!listing_id (
          id,
          lister_id,
          lister:users!lister_id ( username )
        ),
        version:listing_versions!listing_version_id (
          snapshot
        )
        `,
      )
      .eq('creator_id', userId)
      .order('created_at', { ascending: false })
      .returns<ApplicationRow[]>();

    if (fetchError) {
      setError("Couldn't load applications.");
      setRows([]);
    } else {
      setRows(data ?? []);
    }
    setLoading(false);
  }, [userId]);

  useEffect(() => {
    void load();
  }, [load]);

  const byBucket = useMemo(() => {
    const map: Record<Segment, ApplicationRow[]> = {
      pending: [],
      approved: [],
      rejected: [],
      cancelled: [],
    };
    for (const r of rows) {
      map[STATUS_BUCKET[r.status]].push(r);
    }
    return map;
  }, [rows]);

  const visible = byBucket[segment];

  return (
    <SafeAreaView style={styles.root}>
      <ScrollView contentContainerStyle={styles.scroll}>
        <Text style={[textStyles.display, styles.header]}>Applied</Text>
        <SegmentControl active={segment} onChange={setSegment} />

        {loading ? (
          <View style={styles.list} testID="applications-loading">
            <SkeletonCard />
            <SkeletonCard />
          </View>
        ) : error ? (
          <View style={styles.emptyBox}>
            <Text style={[textStyles.body, { color: colors.danger }]}>{error}</Text>
          </View>
        ) : visible.length === 0 ? (
          <View style={styles.emptyBox} testID={`applications-empty-${segment}`}>
            <Text style={[textStyles.body, { color: colors.ink70 }]}>
              {emptyMessageFor(segment)}
            </Text>
          </View>
        ) : (
          <View style={styles.list}>
            {visible.map((row) => (
              <ApplicationRowCard key={row.id} row={row} />
            ))}
          </View>
        )}
      </ScrollView>
    </SafeAreaView>
  );
}

function emptyMessageFor(segment: Segment): string {
  switch (segment) {
    case 'pending':
      return 'No pending applications yet. Apply from Discover.';
    case 'approved':
      return 'Nothing approved yet — keep applying.';
    case 'rejected':
      return 'No rejections here.';
    case 'cancelled':
      return 'No cancelled applications.';
  }
}

type ApplicationRowCardProps = {
  row: ApplicationRow;
  style?: StyleProp<ViewStyle>;
};

function ApplicationRowCard({ row, style }: ApplicationRowCardProps) {
  const title = row.version?.snapshot?.title ?? 'Untitled campaign';
  const handle = row.listing?.lister?.username ?? null;
  const pillStatus: StatusPillStatus = STATUS_BUCKET[row.status];
  const relative = formatRelativeTime(new Date(row.created_at));

  const onPress = useCallback(() => {
    router.push(`/(creator)/listing/${row.listing_id}`);
  }, [row.listing_id]);

  return (
    <Pressable
      onPress={onPress}
      accessibilityRole="button"
      accessibilityLabel={`${title}${handle ? ` by @${handle}` : ''}, ${pillStatus}, applied ${relative}`}
      style={[styles.card, shadows.hard, style]}
      testID={`application-${row.id}`}
    >
      <View style={styles.cardTopRow}>
        <View style={styles.cardTitleBlock}>
          <Text style={[textStyles.h2, { color: colors.ink }]} numberOfLines={2}>
            {title}
          </Text>
          {handle ? (
            <Text style={[textStyles.caption, { color: colors.ink70 }]}>@{handle}</Text>
          ) : null}
        </View>
        <StatusPill status={pillStatus} />
      </View>
      <Text style={[textStyles.caption, { color: colors.ink70 }]}>Applied {relative}</Text>
    </Pressable>
  );
}

const styles = StyleSheet.create({
  root: { flex: 1, backgroundColor: colors.canvas },
  scroll: {
    padding: spacing.base,
    gap: spacing.md,
    paddingBottom: spacing.xxxl,
  },
  header: {
    color: colors.ink,
    marginBottom: spacing.xs,
  },
  segmentRow: {
    flexDirection: 'row',
    flexWrap: 'wrap',
    gap: spacing.sm,
    marginBottom: spacing.xs,
  },
  segment: {
    minHeight: 32,
    paddingHorizontal: spacing.md,
    paddingVertical: spacing.xs + 2,
    borderRadius: radii.pill,
    borderWidth: 2,
    borderColor: colors.ink,
    alignItems: 'center',
    justifyContent: 'center',
  },
  list: {
    gap: spacing.md,
  },
  card: {
    backgroundColor: colors.surface,
    borderColor: colors.ink,
    borderWidth: 2,
    borderRadius: radii.card,
    padding: spacing.base,
    gap: spacing.sm,
  },
  cardTopRow: {
    flexDirection: 'row',
    gap: spacing.sm,
    alignItems: 'flex-start',
  },
  cardTitleBlock: {
    flex: 1,
    gap: spacing.xs,
  },
  emptyBox: {
    padding: spacing.lg,
    alignItems: 'center',
  },
});

